const cbResult = $input.all().find(n => n.json.cb_list !== undefined);
const cbData = cbResult ? cbResult.json : {};
const stockResult = $input.all().find(n => n.json.spot !== undefined);
const stockData = stockResult ? stockResult.json : {};
const ctrlResult = $input.all().find(n => n.json.controller_data !== undefined);
const ctrlData = ctrlResult ? ctrlResult.json : {};
const finResult = $input.all().find(n => n.json.finance_data !== undefined);
const finData = finResult ? finResult.json : {};

const cbList = cbData.cb_list || [];
const spotList = stockData.spot || [];
const maList = stockData.ma || [];
const ctrlList = ctrlData.controller_data || [];
const finList = finData.finance_data || [];

const spotMap = {};
spotList.forEach(s => { spotMap[s['正股代码']] = s; });
const maMap = {};
maList.forEach(m => { maMap[m['正股代码']] = m; });
const ctrlMap = {};
ctrlList.forEach(c => { ctrlMap[c['正股代码']] = c; });
const finMap = {};
finList.forEach(f => { finMap[f['正股代码']] = f; });

const mergedData = cbList.slice(0, 100).map(cb => {
  const stockCode = cb['正股代码'] || cb.stock_code;
  const spot = spotMap[stockCode] || {};
  const ma = maMap[stockCode] || {};
  const ctrl = ctrlMap[stockCode] || {};
  const fin = finMap[stockCode] || {};

  const currentPrice = parseFloat(spot['当前股价']) || 0;
  const pb = parseFloat(spot['PB']) || 1;
  const netAsset = pb ? (currentPrice / pb).toFixed(2) : '';
  const convertPrice = parseFloat(cb['转股价格'] || cb.convert_price) || 0;
  const strongRedeemPrice = convertPrice ? (convertPrice * 1.3).toFixed(2) : '';
  const strongRedeemPct = currentPrice ? (((parseFloat(strongRedeemPrice) / currentPrice - 1) * 100).toFixed(1) + '%') : '';
  const remainScale = parseFloat(cb['可转债剩余规模'] || cb.remaining_scale) || 0;
  const expirePrice = 115;
  const expireScale = (remainScale * expirePrice / 100).toFixed(2);

  const cashEnd = fin['期末现金余额'] || 0;
  const moneyFund = fin['货币资金'] || 0;
  const expireCashRatio = cashEnd ? (expireScale / cashEnd * 100).toFixed(0) + '%' : '';
  const expireMoneyRatio = moneyFund ? (expireScale / moneyFund * 100).toFixed(0) + '%' : '';

  return {
    '正股代码': stockCode,
    '正股名称': cb['正股名称'] || cb.stock_name || '',
    '大股东类型': ctrl['大股东类型'] || '',
    '实际控制人': ctrl['实际控制人'] || '',
    '实控人类型': ctrl['实控人类型'] || '',
    '今日日期': new Date().toISOString().split('T')[0].replace(/-/g, '/'),
    '当前股价': currentPrice || '',
    '每股净资产': netAsset,
    'PB': pb,
    '期末现金余额': fin['期末现金余额'] || '',
    '货币资金': fin['货币资金'] || '',
    '转债代码': cb['转债代码'] || cb.bond_code || '',
    '转债名称': cb['转债名称'] || cb.bond_name || '',
    '可转债剩余规模': remainScale || '',
    '到期赎回价': expirePrice,
    '到期赎回规模': expireScale,
    '赎回规模占期末现金比例': expireCashRatio,
    '赎回规模占货币资金比例': expireMoneyRatio,
    '转股价格': convertPrice || '',
    '强赎价格': strongRedeemPrice,
    '强赎涨幅': strongRedeemPct,
    'MA5': ma['MA5'] || '',
    'MA10': ma['MA10'] || '',
    'MA20': ma['MA20'] || '',
    '到期日期': cb['到期日期'] || cb.expire_date || '',
    '剩余天数': cb['到期日期'] ? Math.floor((new Date(cb['到期日期']) - new Date()) / (1000 * 60 * 60 * 24)) : '',
    '最近公告内容': ''
  };
});

if (mergedData.length === 0) {
  return [{ json: { csv_content: '暂无数据', count: 0, merged_data: [] } }];
}

const headers = Object.keys(mergedData[0]);
const csvRows = [
  headers.join(','),
  ...mergedData.map(row => headers.map(h => {
    const val = row[h] || '';
    return String(val).indexOf(',') > -1 ? ('"' + val + '"') : val;
  }).join(','))
];
const csvContent = csvRows.join('\n');

return [{ json: { csv_content: csvContent, count: mergedData.length, merged_data: mergedData } }];

const csvContent = $input.first().json.csv_content;
const count = $input.first().json.count;
const mergedData = $input.first().json.merged_data;
const today = new Date().toISOString().split('T')[0];

return [{
  json: {
    csv_content: csvContent,
    count: count,
    merged_data: mergedData,
    date: today
  }
}];
